vaidyasya murddhni vinidhaya lilekha bhale tvam rama-dasa iti bho bhava mat-prasadat',NULL,NULL),('cb.antya.4.343','cb','cb.antya.4','ЧБ Антья 4.343',343,NULL,'ksaneko ye karibeka tomara asraya seha rama-padambuja paibe niscaya"',NULL,NULL),('cb.antya.4.344','cb','cb.antya.4','ЧБ Антья 4.344',344,NULL,'murari guptere caitanyera vara suni'' sabei karena maha-jaya-jaya-dhvani',NULL,NULL),('cb.antya.4.345','cb','cb.antya.4','ЧБ Антья 4.345',345,NULL,'ei mata kautuke achena gaura-simha catur-dike sobhe saba caranera bhrnga',NULL,NULL),('cb.antya.4.346','cb','cb.antya.4','ЧБ Антья 4.346',346,NULL,'henai samaye kustha-rogi eka jana prabhura sammukhe asi'' dila darasana',NULL,NULL),('cb.antya.4.347','cb','cb.antya.4','ЧБ Антья 4.347',347,NULL,'dandavata haiya padila arta-nade dui bahu tuli'' maha-arti kari'' kande',NULL,NULL),('cb.antya.4.348','cb','cb.antya.4','ЧБ Антья 4.348',348,NULL,'samsara-uddhara lagi'' tumi krpa-maya prthivira majhe asi'' haila udaya',NULL,NULL),('cb.antya.4.349','cb','cb.antya.4','ЧБ Антья 4.349',349,NULL,'para-duhkha dekhi'' tumi svabhave katara etheke ailun muni tomara gocara',NULL,NULL),('cb.antya.4.350','cb','cb.antya.4','ЧБ Антья 4.350',350,NULL,'kustha-roge pidita, jvalaya muni mari
balaha upaya more kоnа mate tari',NULL,NULL),('cb.antya.4.351','cb','cb.antya.4','ЧБ Антья 4.351',351,NULL,'suni mahaprabhu kustha-rogira vacana balite lagila krodhe kariya tarjana',NULL,NULL),('cb.antya.4.352','cb','cb.antya.4','ЧБ Антья 4.352',352,NULL,'"ghuca ghuca maha-papi, vidyamana haite tore dekhile о papa janmaye lokete',NULL,NULL),('cb.antya.4.353','cb','cb.antya.4','ЧБ Антья 4.353',353,NULL,'parama-dharmika yadi dekhe tora mukha
se divase tahara avaiya haya duhkha',NULL,NULL),('cb.antya.4.354','cb','cb.antya.4','ЧБ Антья 4.354',354,NULL,'vaisnava-nindaka tui papi duracara iha haite duhkha tora kata ache ara',NULL,NULL),('cb.antya.4.355','cb','cb.antya.4','ЧБ Антья 4.355',355,NULL,'ei jvala sahite na para'' dusta-mati ke-mate kariba kumbhipakete vasati',NULL,NULL),('cb.antya.4.356','cb','cb.antya.4','ЧБ Антья 4.356',356,NULL,'ye ''vaisnava'' name haya samsara pavitra
brahmadi gayena ye vaisnava-caritra',NULL,NULL),('cb.antya.4.357','cb','cb.antya.4','ЧБ Антья 4.357',357,NULL,'ye vaisnava bhajile acintya krsna pai
se vaisnava-puja haite bada ara nai',NULL,NULL),('cb.antya.4.358','cb','cb.antya.4','ЧБ Антья 4.358',358,NULL,'''sesa-rama-aja-bhava nija-deha haite vaisnava krsnera priya'' kake bhagavate',NULL,NULL),('cb.antya.4.359','cb','cb.antya.4','ЧБ Антья 4.359',359,NULL,'na tatha me priyatama atma-yonir na sankarah na ca sankarsano na srir naivatma ca yatha bhavan',NULL,NULL),('cb.antya.4.360','cb','cb.antya.4','ЧБ Антья 4.360',360,NULL,'"hena vaisnavera ninda kare yei jana se-i paya duhkha—janma-jivana-marana',NULL,NULL),('cb.antya.4.361','cb','cb.antya.4','ЧБ Антья 4.361',361,NULL,'vidya-kula-tapa saba viphala tahara vaisnava nindaye ye ye papi duracara',NULL,NULL),('cb.antya.4.362','cb','cb.antya.4','ЧБ Антья 4.362',362,NULL,'puja о tahara krsna na kare grahana vaisnavera ninda kare ye papistha jana',NULL,NULL),('cb.antya.4.363','cb','cb.antya.4','ЧБ Антья 4.363',363,NULL,'ye vaisnava nacite prthivi dhanya haya yanra drsti-matra dasa-dike papa ksaya',NULL,NULL),('cb.antya.4.364','cb','cb.antya.4','ЧБ Антья 4.364',364,NULL,'ye vaisnava-jana bahu tuliya nacite svargero sakala vighna ghuce bhala-mate',NULL,NULL);
INSERT OR REPLACE INTO verse_texts (id,verse_id,edition_id,translation,purport) VALUES ('cb.antya.4.243.ru','cb.antya.4.243','cb-ru','"Один твой милостивый взгляд, брошенный на живых существ, пробуждает в их умах привязанность к Кришне".',NULL),('cb.antya.4.244.ru','cb.antya.4.244','cb-ru','"Ты олицетворение преданного служения Вишну. Ты источник энергии, из которого исходит всё".',NULL),('cb.antya.4.245.ru','cb.antya.4.245','cb-ru','"Ты Ганга, ты Деваки, ты Яшода и ты Девахути. Ты Пришни, Анасуйя, Каушалья и Адити".
Шри Гаурасундара прославил Шачидеви, обращаясь к ней как к Яшоде, Деваки, Ганге, Девахути – матери Капилы, Пришни, Анасуйе – матери Даттатрейи, Каушалье и Адити.',NULL),('cb.antya.4.246.ru','cb.antya.4.246','cb-ru','"Всё видимое исходит из тебя. Ты созидательница и в конечном счёте, всё погружается в тебя".',NULL),('cb.antya.4.247.ru','cb.antya.4.247','cb-ru','"Кому по силам описать твою славу? Ты пребываешь в сердце каждого".',NULL),('cb.antya.4.248.ru','cb.antya.4.248','cb-ru','Таким образом, Господь, устанавливающий религиозные принципы, предложил поклоны и прочитал стихи.',NULL),('cb.antya.4.249.ru','cb.antya.4.249','cb-ru','Кто кроме Кришны может проявить такую преданность отцу, матери, или старшим?',NULL),('cb.antya.4.250.ru','cb.antya.4.250','cb-ru','Когда Господь читал стихи и предлагал поклоны, слёзы любви омывали всё Его тело.',NULL),('cb.antya.4.251.ru','cb.antya.4.251','cb-ru','Как только Шачимата увидела лицо Господа Гауранги, её охватил трансцендентный экстаз.',NULL),('cb.antya.4.252.ru','cb.antya.4.252','cb-ru','Пока Господь Вайкунтхи с почтением предлагал ей молитвы, она стояла застыв как деревянная кукла.',NULL),('cb.antya.4.253.ru','cb.antya.4.253','cb-ru','Господь сказал, "Лишь по твоей милости у Меня появилась преданность к Кришне".',NULL),('cb.antya.4.254.ru','cb.antya.4.254','cb-ru','"Если слуга слуги, слуги и так миллионы раз, имеет отношение к тебе, то для Меня он дороже, чем Моя собственная жизнь".
Учитывая, что с матерью Верховного Господа были связаны бесчисленные слуги и служанки, Шри Гаурасундара сказал, "Благодаря тому, что они так или иначе связаны с тобой, они очень дороги Мне".',NULL),('cb.antya.4.255.ru','cb.antya.4.255','cb-ru','"Если человек хотя бы один раз вспомнит о тебе, он никогда не погрязнет в материальных привязанностях".',NULL),('cb.antya.4.256.ru','cb.antya.4.256','cb-ru','"Ганга и туласи прославились тем, что очищают всё. Но даже они становятся чище от твоего прикосновения".',NULL),('cb.antya.4.257.ru','cb.antya.4.257','cb-ru','"У меня нет возможности отплатить тебе за подаренную Мне любовь".',NULL),('cb.antya.4.258.ru','cb.antya.4.258','cb-ru','"Поэтому пусть твои собственные хорошие качества станут наградой за привязанность, которую ты всё время испытываешь ко Мне".',NULL),('cb.antya.4.259.ru','cb.antya.4.259','cb-ru','Таким образом, пока Господь с огромной радостью возносил молитвы, все вайшнавы купались в океане экстаза.',NULL),('cb.antya.4.260.ru','cb.antya.4.260','cb-ru','Шачимата знала, что её сын был Господом Нараяной, который появился на земле, и мог говорить всё, что пожелает.',NULL),('cb.antya.4.261.ru','cb.antya.4.261','cb-ru','Через несколько мгновений матушка Шачи просто сказала, "Кто способен понять Твои слова?"',NULL),('cb.antya.4.262.ru','cb.antya.4.262','cb-ru','"Обусловленные души подобны беспомощным мёртвым телам, которые швыряют волны бушующего океана".
Смотри Шримад Бхагаватам (6.15.3).',NULL),('cb.antya.4.263.ru','cb.antya.4.263','cb-ru','"Все живые существа в океане материального существования, вынуждены действовать повинуясь Твоей иллюзорной энергии".',NULL),('cb.antya.4.264.ru','cb.antya.4.264','cb-ru','"Мой дорогой сын, всё что я могу сказать, так это то, что Ты один знаешь что хорошо для каждого".',NULL),('cb.antya.4.265.ru','cb.antya.4.265','cb-ru','"Я понимаю, что обходя кого-то по кругу, вознося молитвы, или предлагая поклоны, Ты действуешь исключительно по собственной воле".',NULL),('cb.antya.4.266.ru','cb.antya.4.266','cb-ru','Выслушав слова матушки Шачи, все преданные Господа дружно воскликнули, "Джая! Джая!"',NULL),('cb.antya.4.267.ru','cb.antya.4.267','cb-ru','Гаурачандра появился из утробы матери Шачи, поэтому, кто может описать пределы её преданного служения?',NULL),('cb.antya.4.268.ru','cb.antya.4.268','cb-ru','Даже если кто-то произносит слово ай как мирское слово, благодаря его влиянию человек освобождается от всех страданий.
Если уважаемую Шачидеви, мать Гауры, кто-то назовёт языком невежд как ай, то он избавится от всех своих страданий.',NULL),('cb.antya.4.269.ru','cb.antya.4.269','cb-ru','Матушка Шачи была совершенно счастлива, увидев Господа, а преданные от восторга потеряли связь с внешним сознанием.',NULL),('cb.antya.4.270.ru','cb.antya.4.270','cb-ru','Не во власти человеческого существа описать счастье, переживаемое присутствующими.',NULL),('cb.antya.4.271.ru','cb.antya.4.271','cb-ru','Когда сильно опьянённый вкусами любви Нитьянанда увидел как счастлива Шачи, Он с радостью окунулся в океан трансцендентного экстаза.',NULL),('cb.antya.4.272.ru','cb.antya.4.272','cb-ru','Ачарья Госани предложил Шачимате бесчисленные поклоны и вознёс молитвы, прославляющие Деваки.
Стих 273-274
Преданные, возглавляемые Харидасом, Мурари, Шригарбхой, Нараяной, Джагадишей и Гопинатхой, увидев материнскую радость Шачи, пришли в такой восторг, что казалось они слились воедино в трансцендентном экстазе.',NULL),('cb.antya.4.275.ru','cb.antya.4.275','cb-ru','Любой, кто читает или слушает повествование об этих восторженных играх, безусловно обретёт сокровище экстатической любви к Кришне.',NULL),('cb.antya.4.276.ru','cb.antya.4.276','cb-ru','Затем, Адвайта испросил разрешение Господа на то, чтобы счастливая Шачимата приготовила для Него еду.',NULL),('cb.antya.4.277.ru','cb.antya.4.277','cb-ru','Когда совершенно счастливая Шачи пошла готовить, она с любовью подумала, "Гаурачандра – это Сам Господь Нараяна".',NULL),('cb.antya.4.278.ru','cb.antya.4.278','cb-ru','Матушка Шачи приготовила такое изобилие овощных блюд, что я затрудняюсь перечислить все и даже не знаю всех их названий.',NULL),('cb.antya.4.279.ru','cb.antya.4.279','cb-ru','Мать Шачи знала, что Господь просто обожал шаку (шпинат), и приготовила двадцать разнообразных блюд.',NULL),('cb.antya.4.280.ru','cb.antya.4.280','cb-ru','Затем Шачимата с огромным удовольствием приготовила каждый вид овощей десятью и даже двадцатью различными способами.',NULL),('cb.antya.4.281.ru','cb.antya.4.281','cb-ru','Закончив готовку многочисленных яств, она принесла их в столовую.',NULL),('cb.antya.4.282.ru','cb.antya.4.282','cb-ru','Она выложила рис и овощи на тарелки, а сверху украсила порции листиками туласи.
Фраза упашкара кари означает "правильно сервированный" (на блюде).',NULL),('cb.antya.4.283.ru','cb.antya.4.283','cb-ru','Она положила рис и приготовленные овощи рядами вокруг удобного сидения, которое устроила в середине.',NULL),('cb.antya.4.284.ru','cb.antya.4.284','cb-ru','Затем пришёл Махапрабху вместе со Своими спутниками.',NULL),('cb.antya.4.285.ru','cb.antya.4.285','cb-ru','Когда Господь увидел красиво расставленные блюда с рисом и овощами, Он почтительно предложил Свои поклоны.',NULL),('cb.antya.4.286.ru','cb.antya.4.286','cb-ru','Господь сказал, "Что говорить о употреблении в пищу этого риса, если человек освобождается от материальных оков, просто глядя на него".
Шри Шачидеви приготовила двадцать видов шаки и от десяти до двадцати разнообразных овощных блюд. Украсив их сверху туласи манджари, она предложила всё это Вишну. Когда Гаурасундара увидел это предложение, Он почтил еду поклонами и сказал, "Что говорить о благе от еды этих яств, если один взгляд на предложенную пищу освобождает от привязанности к наслаждениям этого материального мира. В любом, кто почувствует божественный аромат этого риса, пробудится склонность к служению Кришне".',NULL),('cb.antya.4.287.ru','cb.antya.4.287','cb-ru','"Я не в состоянии описать приготовленные блюда. Один запах этого риса пробуждал преданность Кришне".',NULL),('cb.antya.4.288.ru','cb.antya.4.288','cb-ru','"Я думаю, Кришна и Его спутники лично насладились этим рисом".',NULL),('cb.antya.4.289.ru','cb.antya.4.289','cb-ru','После этих слов, Господь Гауранга обошёл рис и уселся поесть.',NULL),('cb.antya.4.290.ru','cb.antya.4.290','cb-ru','По указанию Господа все Его спутники сели вокруг, чтобы посмотреть на трапезу Господа.',NULL),('cb.antya.4.291.ru','cb.antya.4.291','cb-ru','Когда Господь Вайкунтхи принялся за еду, удачливая Шачимата смотрела на Него полными счастья глазами.',NULL),('cb.antya.4.292.ru','cb.antya.4.292','cb-ru','Господь с огромным удовольствием отведал каждое из овощных блюд.',NULL),('cb.antya.4.293.ru','cb.antya.4.293','cb-ru','Тем не менее, из всех изысков, блюда из шаки были самыми востребованными, и Господь много раз возвращался к ним.',NULL),('cb.antya.4.294.ru','cb.antya.4.294','cb-ru','Глядя как Господь любит шаку, все преданные радостно улыбались.',NULL),('cb.antya.4.295.ru','cb.antya.4.295','cb-ru','Господь тоже улыбался и во время еды нахваливал шаку.',NULL),('cb.antya.4.296.ru','cb.antya.4.296','cb-ru','Господь сказал, "Не зря шаку называют ачьютой. Эта пища развивает в человеке привязанность к Кришне".
Ачьюта это один из видов шаки. Во время трапезы Господь прославлял различные качества всех видов шаки и объяснял, как эта пища пробуждает отношения с Кришной.',NULL),('cb.antya.4.297.ru','cb.antya.4.297','cb-ru','"Тот, кто употребляет в пищу патала шаку, вастука шаку и кала шаку, будет рождение за рождением наслаждаться общением с вайшнавами".',NULL),('cb.antya.4.298.ru','cb.antya.4.298','cb-ru','"Тот кто ест салинча шаку и хеленча шаку, не будет болеть и достигнет преданного служения Кришне".',NULL),('cb.antya.4.299.ru','cb.antya.4.299','cb-ru','Волосы на теле Господа стояли дыбом, пока Он во время трапезы рассказывал о славе различных видов шаки.',NULL),('cb.antya.4.300.ru','cb.antya.4.300','cb-ru','Только тысячеголовый Ананта знает, какое счастье испытал в тот день Господь, наслаждаясь едой.',NULL),('cb.antya.4.301.ru','cb.antya.4.301','cb-ru','Изначальный Господь Ананта, который поддерживает вселенные, постоянно прославляет эти игры тысячами языков.',NULL),('cb.antya.4.302.ru','cb.antya.4.302','cb-ru','Тот же Господь явился в Кали-югу, как Авадхута Нитьянанда Прабху. Исполняя Его указание, я описываю эти игры.',NULL),('cb.antya.4.303.ru','cb.antya.4.303','cb-ru','Мудрецы во главе с Ведавьясой, в подробностях опишут эти славные игры.',NULL),('cb.antya.4.304.ru','cb.antya.4.304','cb-ru','Если живое существо слушает или читает описания этих славных игр, оно освобождается от оков невежества.',NULL),('cb.antya.4.305.ru','cb.antya.4.305','cb-ru','Завершив Свою трапезу, Махапрабху омыл руки и сел.',NULL),('cb.antya.4.306.ru','cb.antya.4.306','cb-ru','Как только Господь омыл руки, преданные начали делить остатки Его еды.',NULL),('cb.antya.4.307.ru','cb.antya.4.307','cb-ru','Кто-то сказал, "Разве брахману полагается есть остатки? Я шудра, поэтому мне положено их есть".',NULL),('cb.antya.4.308.ru','cb.antya.4.308','cb-ru','Кто-то сказал: "Я не брахман", а другой человек схватил часть еды и убежал.',NULL),('cb.antya.4.309.ru','cb.antya.4.309','cb-ru','Кто-то сказал, "Шудрам не положено принимать остатки пищи. Им следует сперва разобраться, что правильно, а что нет, руководствуясь писаниями".',NULL),('cb.antya.4.310.ru','cb.antya.4.310','cb-ru','Другой человек сказал: "Мне не нужно никаких остатков, я просто возьму пустую тарелку и уйду".',NULL),('cb.antya.4.311.ru','cb.antya.4.311','cb-ru','Кто-то ещё сказал: "Я всегда раньше собирал пустые тарелки, но сейчас, отбросив гордыню, ты принялся исполнять мои обязанности".',NULL),('cb.antya.4.312.ru','cb.antya.4.312','cb-ru','Таким образом, неугомонные преданные с нетерпением оказывали почтение нектарным остаткам еды Господа.
Все классы преданных почтили остатки трапезы Господа. Те, кто считали себя шудрами говорили, что только они имеют право питаться остатками еды Господа. Кто-то тихонько схватил какую-то часть еды и убежал. Другой говорил, что шудры не достаточно сведущи, чтобы принимать прасад Господа, и это позволительно только сведущим брахманам. Кто-то ещё говорил, что в его обязанности входит очистка тарелок от остатков еды, и что только он один имеет право касаться тарелок Господа.',NULL),('cb.antya.4.313.ru','cb.antya.4.313','cb-ru','Кто же не жаждал насладиться остатками пищи, которая была приготовлена матушкой Шачи и опробована самим Господом?',NULL),('cb.antya.4.314.ru','cb.antya.4.314','cb-ru','Закончив приём благостной пищи, все преданные собрались перед Господом.',NULL),('cb.antya.4.315.ru','cb.antya.4.315','cb-ru','Все спутники Господа Гаурасундары уселись вокруг Него.',NULL),('cb.antya.4.316.ru','cb.antya.4.316','cb-ru','Когда Господь увидел перед Собой Мурари Гупту, Он с улыбкой обратился к нему.',NULL),('cb.antya.4.317.ru','cb.antya.4.317','cb-ru','"О Гупта, Я слышал, что ты написал восемь стихов, описывающих Рагхавендру.
Пожалуйста, прочитай их".',NULL),('cb.antya.4.318.ru','cb.antya.4.318','cb-ru','От просьбы Господа, Мурари Гупта погрузился в экстаз и начал читать свои стихи.',NULL),('cb.antya.4.319.ru','cb.antya.4.319','cb-ru','"Я непрестанно поклоняюсь Господу Рамачандре, гуру трёх миров. Рядом с Ним стоит Шри Лакшмана, лучший из лучников, тело которого сверкает как расплавленное золото. Он преданно служит своему старшему брату, который прекрасен и нарядно одет, и олицетворяет Ананту Шешу".',NULL),('cb.antya.4.320.ru','cb.antya.4.320','cb-ru','"Я непрестанно склоняюсь перед Господом Рамачандрой, гуру трёх миров, который уничтожил Кхару, Триширу, Камбандху и их приспешников, избавил лес Дандакаранья от демона Душаны и убил Вали, подружившись с Сугривой".',NULL),('cb.antya.4.321.ru','cb.antya.4.321','cb-ru','Таким образом, Мурари Гупта прочитал восемь стихов, и по просьбе Господа дал им свои объяснения.
Остальные шесть стихов Рамаштаки, можно найти во второй пракраме седьмой сарги Шри Чайтанья-чарита-махакавьи, вот они:
"Его лицо, безупречное как луна, сияет ярче сверкающих в короне бриллиантов, а две серьги напоминают восходящие в вечернем небе Юпитер и Венеру. Я в бесконечных молитвах склоняюсь перед Господом Шри Рамой, гуру трёх миров".
.
netra su-bimba-dasana-cchada-caru-nasam subhrasu-rasmi-parinirjjita-caru-hasa ramam jagat-traya-gurum satatam bhajami
"Его лотосные глаза источают сияние, словно лучи раннего восходящего солнца. Его ярко алые губы прекрасны как плоды бимбы. Безупречный нос и обезоруживающая улыбка, обнажающая белоснежные зубы, затмевают сияние луны. Я в бесконечных молитвах склоняюсь перед Господом Шри Рамой, источником наслаждения и гуру трёх миров".
"Подобная изящной раковине шея нерождённого Господа, украшена золотой нитью ожерелья, сверкающего словно молния в грозовых облаках. Его шея нежна, словно лотос в окружении стаи цапель. Я в бесконечных молитвах склоняюсь перед Господом Шри Рамой, гуру трёх миров".
panca-cchadadhika-sata pravarangulibhih kurvvaty аsitа-kаnаkа-dyuti yasya sita parsve ''sti ta raghu-vara satata bhajami
"На поднятой ладони Сита держит цветок лотоса с тысячей лепестков, пять из которых – её изящные пальцы. Я в бесконечных молитвах склоняюсь перед Господом Рамой, лучшим из династии Рагху, неразлучным с Ситой, сияющей как расплавленное золото".
marica-rakasa-subahu-mukhan nihatya yajna raraka kusikanvaya-punya-rasi ramam jagat-traya-gurum satatam bhajami
"Лучший из династии Рагху, подобный луне, убил демонов Маричу и Субаху, дав Вишвамитре почтить память предков. Я в бесконечных молитвах склоняюсь перед Господом Рамой, гуру трёх миров".
.
vaivahikotsava-vidhi pathi bhargavendram jitva pitur mudam uvaha kakutstha-varya ramam jagat-traya-gurum satatam bhajami
"Сломав лук Шивы, Он взял в супруги дочь царя Джанаки – Ситу. Тогда, возвращаясь домой, Он одолел могучего Парашураму, лучшего из династии Бхригу, доставив радость отцу. Я в бесконечных молитвах склоняюсь перед Господом Рамой, лучшим из потомков Какутстхи и гуру трёх миров".',NULL),('cb.antya.4.322.ru','cb.antya.4.322','cb-ru','"Его тело имеет оттенок травы дурва, и он Верховный учитель в искусстве стрельбы из лука. Он подобен древу желаний, исполняя чаяния Своих преданных".
Фраза коданда-дикша-гуру относится к дханур-видье – мастеру стрельбы из лука.',NULL),('cb.antya.4.323.ru','cb.antya.4.323','cb-ru','"Он улыбается, восседая на царском троне, украшенном драгоценными камнями.
Шри Джанакидеви стоит от Него слева".',NULL),('cb.antya.4.324.ru','cb.antya.4.324','cb-ru','"Перед Ним Его младший брат, великий лучник Лакшмана, тело которого сияет ярче золота, которым Он украшен".',NULL),('cb.antya.4.325.ru','cb.antya.4.325','cb-ru','"Явившись как младший брат Господа, Шри Лакшмана, который является изначальным Господом Анантой, преданно служил Своему старшему брату".',NULL),('cb.antya.4.326.ru','cb.antya.4.326','cb-ru','"Рождение за рождением я поклоняюсь лотосным стопам Шри Рагхунанданы, который является Верховным учителем каждого".',NULL),('cb.antya.4.327.ru','cb.antya.4.327','cb-ru','"Два Его брата, Бхарата и Шатругхна овевают Его чамарами, пока вожди племени обезьян воспевают Его славу".',NULL),('cb.antya.4.328.ru','cb.antya.4.328','cb-ru','"Дай мне Господь, друг чандалы Гухи, рождение за рождением петь Тебе славу".',NULL),('cb.antya.4.329.ru','cb.antya.4.329','cb-ru','"Он оставил царство по указанию Своего гуру. Он скитался по лесам, доставляя Своими деяниями радость полубогам".',NULL),('cb.antya.4.330.ru','cb.antya.4.330','cb-ru','"Господь убил Вали и вручил царство Сугриве. Из сострадания О стал другом Сугривы".',NULL),('cb.antya.4.331.ru','cb.antya.4.331','cb-ru','"Я кланяюсь лотосным стопам наставника трёх миров, рождённого Ахальей".',NULL),('cb.antya.4.332.ru','cb.antya.4.332','cb-ru','"С помощью Лакшманы и обезьян Господь без труда построил мост через непреодолимый океан".',NULL),('cb.antya.4.333.ru','cb.antya.4.333','cb-ru','"Я поклоняюсь лотосным стопам Господа, который убил Равану со всеми членами его семьи. Даже Индра не мог справиться с ними".',NULL),('cb.antya.4.334.ru','cb.antya.4.334','cb-ru','"По Его милости праведный Вибхишана стал царём Ланки, хотя и не хотел этого".',NULL),('cb.antya.4.335.ru','cb.antya.4.335','cb-ru','"Я поклоняюсь лотосным стопам Рагхавендры, слава которого достигла ушей даже яванов".',NULL),('cb.antya.4.336.ru','cb.antya.4.336','cb-ru','"Он всегда был вооружён луком и стрелами, уничтожал злодеев и защищал своих подданных, как собственных сыновей".',NULL),('cb.antya.4.337.ru','cb.antya.4.337','cb-ru','"По Его милости все жители Айодхьи отправились на Вайкунтху в своих собственных телах".',NULL),('cb.antya.4.338.ru','cb.antya.4.338','cb-ru','"Махешвара, поглощённый вкусами Его имён забывает об одежде, а Лакшми постоянно занята служением Его лотосным стопам".',NULL),('cb.antya.4.339.ru','cb.antya.4.339','cb-ru','"Я поклоняюсь лотосным стопам Рагхавендры, учителя всех. Веды прославляют Его как Верховный Брахман и как Господа вселенных".',NULL),('cb.antya.4.340.ru','cb.antya.4.340','cb-ru','Таким образом, Мурари Гупта объяснил восемь стихов, которые он сочинил, описав нектарную славу Рамы.',NULL),('cb.antya.4.341.ru','cb.antya.4.341','cb-ru','Выслушав молитвы, довольный Шри Гаурасундара поместил Свою лотосную стопу на голову Мурари.',NULL),('cb.antya.4.342.ru','cb.antya.4.342','cb-ru','"Послушай, Гупта, по Моей милости ты неизменно будешь слугой Рамы, рождение за рождением".
Во второй пракраме седьмой сарги Чайтанья-чариты и в двенадцатой волне Бхакти-ратнакары, сказано:
"Услышав эти восемь стихов, сочиненных лекарем Мурари, описывающих Шри Раму, лев среди царей и услада династии Рагху, Верховный Господь Гаурахари поместил Свою стопу на голову Мурари, и начертал на его лбу Рама даса. Затем, Он провозгласил, "О Мурари, по Моей милости, ты будешь вечным преданным Шри Рамы".',NULL),('cb.antya.4.343.ru','cb.antya.4.343','cb-ru','"Если человек хотя бы на мгновение найдёт у тебя прибежище, то он безусловно, достигнет лотосных стоп Рамы".',NULL),('cb.antya.4.344.ru','cb.antya.4.344','cb-ru','Когда преданные услышали благословение, которое Господь Чайтанья дал Мурари, все дружно воскликнули: "Джая! Джая!"',NULL),('cb.antya.4.345.ru','cb.antya.4.345','cb-ru','Таким образом, подобный льву Гаура наслаждался Своими играми в окружении Своих преданных, которые как шмели вились у Его лотосных стоп.',NULL),('cb.antya.4.346.ru','cb.antya.4.346','cb-ru','Тем временем туда пришёл один прокажённый и предстал перед Господом.',NULL),('cb.antya.4.347.ru','cb.antya.4.347','cb-ru','Он упал перед Господом, подняв обе руки и жалобно заплакал.',NULL),('cb.antya.4.348.ru','cb.antya.4.348','cb-ru','Он сказал: "О, милостивый Господь, Ты явился в этот мир, чтобы освобождать живых существ".',NULL),('cb.antya.4.349.ru','cb.antya.4.349','cb-ru','"Ты по Своей природе не можешь равнодушно взирать на страдания других людей.
Поэтому я пришёл к Тебе".',NULL),('cb.antya.4.350.ru','cb.antya.4.350','cb-ru','"Я страдаю от проказы, и всё моё тело пылает. Пожалуйста, скажите мне, как избавиться от этой напасти?"',NULL),('cb.antya.4.351.ru','cb.antya.4.351','cb-ru','Выслушав слова прокажённого, Махапрабху в гневном настроении начал его отчитывать.',NULL),('cb.antya.4.352.ru','cb.antya.4.352','cb-ru','"Убирайся отсюда, великий грешник! Уйди с глаз долой! Один твой облик делает людей грешниками".
Фраза гхуча гхуча означает "исчезни, потеряйся".',NULL),('cb.antya.4.353.ru','cb.antya.4.353','cb-ru','"Даже самый благочестивый человек увидев твоё лицо, безусловно, в тот же день столкнётся с бедой".',NULL),('cb.antya.4.354.ru','cb.antya.4.354','cb-ru','"Ты самый грешный, презренный хулитель вайшнавов. Тебя ожидают куда большие страдания".',NULL),('cb.antya.4.355.ru','cb.antya.4.355','cb-ru','"О нечестивец, ты не можешь терпеть эту жгучую боль, но как ты собираешься сносить страдания в аду Кумбхипака?"',NULL),('cb.antya.4.356.ru','cb.antya.4.356','cb-ru','"Весь мир очищается повторением имён вайшнавов, а полубоги во главе с Брахмой прославляют их качества".',NULL),('cb.antya.4.357.ru','cb.antya.4.357','cb-ru','"Нет ничего возвышенней, чем поклонение вайшнавам, потому что поклоняясь им, человек обретает непостижимого Господа Кришну".',NULL),('cb.antya.4.358.ru','cb.antya.4.358','cb-ru','"В Шримад-Бхагаватам Кришна провозглашает, что вайшнав для Него дороже чем Шеша, Лакшми, Брахма, Шива и Его собственное тело".',NULL),('cb.antya.4.359.ru','cb.antya.4.359','cb-ru','"О Уддхава, ни мой сын Брахма, ни Шанкара, как Моя форма, ни мой брат Санкаршана, ни Моя супруга Лакшми не дороги Мне так, как ты – Мой преданный. Более того, даже Я сам не так себе дорог".',NULL),('cb.antya.4.360.ru','cb.antya.4.360','cb-ru','"Поэтому любой кто поносит такого вайшнава, обречён испытывать страдания рождаясь, живя и умирая".',NULL),('cb.antya.4.361.ru','cb.antya.4.361','cb-ru','"Образование, знатное рождение и аскезы грешного, презренного человека, который хулит вайшнавов – ничего не стоят".',NULL),('cb.antya.4.362.ru','cb.antya.4.362','cb-ru','"Кришна не принимает поклонение грешного человека, оскорбляющего вайшнавов".',NULL),('cb.antya.4.363.ru','cb.antya.4.363','cb-ru','"Когда вайшнав танцует, земля обретает славу, а его мимолётный взгляд уничтожает грехи во всех десяти сторонах света".',NULL),('cb.antya.4.364.ru','cb.antya.4.364','cb-ru','"Когда вайшнав поднимает руки и танцует, на небесных планетах без следа исчезает всё неблагоприятное".
Смотри стихи 182-184
второй главы Ади-кханды.',NULL);